147	// EvaluateLifecycleQueue derives queue state from caller-provided facts. Legacy
148	// lifecycle labels are reported as warnings only; they never choose the bucket.
149	func EvaluateLifecycleQueue(f LifecycleQueueFacts) LifecycleQueueDecision {
150		decision := LifecycleQueueDecision{
151			DependenciesSatisfied: LifecycleDependenciesSatisfied(f.Dependencies),
152			SatisfiesDependents:   LifecycleStatusSatisfiesDependency(f.Status),
153		}
154		decision.Warnings = append(decision.Warnings, lifecycleLegacyLabelWarnings(f.LegacyLabels)...)
155		for _, warning := range f.LegacyMigrationWarnings {
156			trimmed := strings.TrimSpace(warning)
157			if trimmed == "" {
158				continue
159			}
160			decision.Issues = append(decision.Issues, LifecycleIssue{
161				Code:   LifecycleIssueLegacyMigrationCompatibility,
162				Detail: trimmed,
163			})
164			decision.Warnings = append(decision.Warnings, trimmed)
165		}
166	
167		if err := validateLifecycleStatus(f.Status); err != nil {
168			decision.Bucket = LifecycleBucketInvalid
169			decision.Issues = append(decision.Issues, LifecycleIssue{
170				Code:   LifecycleIssueInvalidStatus,
171				Detail: err.Error(),
172			})
173			return decision
174		}
175	
176		switch f.Status {
177		case StatusClosed:
178			decision.Bucket = LifecycleBucketClosedTerminal
179		case StatusCancelled:
180			decision.Bucket = LifecycleBucketCancelledTerminal
181		case StatusProposed:
182			decision.Bucket = LifecycleBucketProposed
183			decision.OperatorAttention = true
184		case StatusInProgress:
185			if f.ClaimFresh {
186				decision.Bucket = LifecycleBucketClaimed
187				return decision
188			}
189			decision = evaluateOpenLifecycleQueue(f, decision)
190		case StatusBlocked:
191			decision.Bucket = LifecycleBucketBlockedExternal
192			decision.ExternalBlockerReason = strings.TrimSpace(f.ExternalBlockerReason)
193			if decision.ExternalBlockerReason == "" {
194				decision.Issues = append(decision.Issues, LifecycleIssue{
195					Code:   LifecycleIssueBlockedMissingExternalReason,
196					Detail: "blocked status requires an explicit external blocker reason",
197				})
198			}
199		case StatusOpen:
200			if f.ClaimFresh {
201				decision.Bucket = LifecycleBucketClaimed
202				return decision
203			}
204			decision = evaluateOpenLifecycleQueue(f, decision)
205		}
206		return decision
207	}
